UBYTE iss_map_get_pen(UBYTE depth, WORD x, WORD y)
{
    ULONG idx;
    UBYTE v;
    if (x < 0) x = 0;
    if (y < 0) y = 0;
    if (x >= ISS_MAP_SRC_W) x = ISS_MAP_SRC_W - 1;
    if (y >= ISS_MAP_SRC_H) y = ISS_MAP_SRC_H - 1;
    idx = (ULONG)y * ISS_MAP_SRC_W + (ULONG)x;
    if (depth >= 4) {
        v = iss_map_4bpp[idx >> 1];
        if (idx & 1) return (UBYTE)(v & 15);
        return (UBYTE)((v >> 4) & 15);
    }
    v = iss_map_2bpp[idx >> 2];
    return (UBYTE)((v >> (6 - ((idx & 3) * 2))) & 3);
}
